import{_ as e,o as i,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"17. Rights Of Private Practice Administration","description":"","frontmatter":{"title":"17. Rights Of Private Practice Administration","eba":"Medical Specialists 2022-2026","topics":["employment"]},"headers":[],"relativePath":"ebas/medical-specialists/employment/17-rights-of-private-practice-administration.md","filePath":"ebas/medical-specialists/employment/17-rights-of-private-practice-administration.md"}'),o={name:"ebas/medical-specialists/employment/17-rights-of-private-practice-administration.md"};function n(s,t,c,p,h,l){return i(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="_17-rights-of-private-practice-administration" tabindex="-1">17. Rights Of Private Practice Administration <a class="header-anchor" href="#_17-rights-of-private-practice-administration" aria-label="Permalink to &quot;17. Rights Of Private Practice Administration&quot;">​</a></h1><p><strong>17.1</strong> Where a Doctor engages the Health Service as agent to bill his or her private patients:</p><p><strong>(a)</strong> the Health Service must ensure:</p><p><strong>(i)</strong> that no account is rendered which could place the Doctor in breach of the Health Insurance Act 1973;</p><p><strong>(ii)</strong> that the Doctor is provided with monthly reports at the major account level which can be supplemented with information at transaction level if required by the Doctor;</p><p><strong>(iii)</strong> that the process of billing and records of incoming and outgoing funds are complete, transparent and available upon request to the Doctor;</p><p><strong>(iv)</strong> that informed financial consent is taken; and</p><p><strong>(v)</strong> that processes are consistent with the requirements of the National Healthcare Agreements (however titled) particularly in relation to private patient election.</p><p><strong>(b)</strong> The Doctor must ensure they provide the Health Service any relevant information required (i.e. Provider number) to facilitate the obligations of the Health Service set out in (a) above.</p>',9)])])}const g=e(o,[["render",n]]);export{m as __pageData,g as default};
